WebSocket Transport
For browser clients or when you need HTTP compatibility.
// Browser or Node.js
const client = await SaikuroClient.connect(&quot;ws://localhost:7700&quot;);

async with SaikuroClient.connect(&quot;ws://localhost:7700&quot;) as client:
